import heapq

def solve(n: int, edges: list[list[int]]) -> int:
    adj = [[] for _ in range(n)]
    for u, v, s, e in edges:
        adj[u].append((v, s, e))

    INF = float('inf')
    distance = [INF] * n
    distance[0] = 0
    heap = [(0, 0)]

    while heap:
        current_time, u = heapq.heappop(heap)
        if u == n - 1:
            return current_time
        if current_time > distance[u]:
            continue
        for v, s, e in adj[u]:
            earliest_time = max(current_time, s)
            if earliest_time <= e:
                next_time = earliest_time + 1
                if next_time < distance[v]:
                    distance[v] = next_time
                    heapq.heappush(heap, (next_time, v))

    return -1
